{
  "domain_analysis": {
    "business_context": "Evolution of the Shipment aggregate from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is a fundamental structural change to a core domain entity in a delivery platform with 2M existing shipments and external partner API integrations. This is not a minor enhancement — it redefines what a Shipment *is*.",
    "bounded_context": "Shipment / Delivery Management",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of goods being transported from origin to one or more delivery destinations. The aggregate root that owns Recipients." },
      { "term": "Recipient", "definition": "A party who receives a delivery. Identified by name, address, and phone number. Now a first-class collection member within a Shipment rather than an embedded singular value." },
      { "term": "Delivery Preferences", "definition": "Recipient-specific instructions governing how, when, and where a delivery should be made (e.g., time windows, safe-place authorization, signature requirements, contactless delivery)." },
      { "term": "Primary Recipient", "definition": "The first or default recipient on a multi-recipient shipment. Critical for backward compatibility — legacy integrations and reports must be able to resolve a single canonical recipient." },
      { "term": "Multi-Recipient Shipment", "definition": "A shipment with more than one recipient, each potentially at a different address with different delivery preferences. Requires per-recipient delivery status tracking." },
      { "term": "Delivery Status", "definition": "The fulfillment state of a delivery. In multi-recipient shipments, each recipient has an independent delivery status (e.g., one delivered, one failed)." },
      { "term": "Partner API", "definition": "External integrations that consume shipment data in the current single-recipient format. These represent contractual interfaces that cannot be changed unilaterally." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment MUST have at least one Recipient at all times. An empty recipient list is invalid.",
      "invariant": true,
      "invariant_justification": "A shipment with zero recipients has no delivery destination and is physically meaningless — it cannot be routed, delivered, or invoiced. This is a data integrity constraint.",
      "testable_assertion": "Any attempt to create a Shipment with zero Recipients, or to remove the last Recipient from a Shipment, MUST be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient MUST have a non-empty name, a valid address, and a valid phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum identifiers required for physical delivery and customer contact. Without them, a courier cannot complete delivery or notify the recipient.",
      "testable_assertion": "Persisting a Recipient with a null/empty name, null/invalid address, or null/invalid phone number MUST fail validation."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient within a Shipment MUST be uniquely addressable — no two Recipients on the same Shipment may share the same address AND name combination.",
      "invariant": true,
      "invariant_justification": "Duplicate recipients on the same shipment would cause double-delivery, double-invoicing, and courier confusion. This is a data consistency constraint.",
      "testable_assertion": "Adding a Recipient whose (name, address) tuple already exists on the Shipment MUST be rejected."
    },
    {
      "id": "BR-4",
      "rule": "Delivery Preferences are optional and belong to each Recipient independently. If not specified, system defaults apply.",
      "invariant": false,
      "invariant_justification": "Delivery preferences are policy-driven defaults that can change. A business decision could alter the default from signature-required to contactless.",
      "testable_assertion": "A Recipient with no explicit delivery preferences MUST receive system-default preferences. One Recipient's preferences MUST NOT affect another Recipient on the same Shipment."
    },
    {
      "id": "BR-5",
      "rule": "Each Recipient on a multi-recipient Shipment MUST have an independent delivery status tracked separately.",
      "invariant": true,
      "invariant_justification": "In a multi-recipient shipment, one recipient may be delivered while another fails. A single shipment-level status would misrepresent reality and corrupt operational data.",
      "testable_assertion": "Marking delivery complete for Recipient A on a Shipment MUST NOT change the delivery status of Recipient B on the same Shipment."
    },
    {
      "id": "BR-6",
      "rule": "The overall Shipment status is a derived value computed from the statuses of all its Recipients. A Shipment is 'delivered' only when ALL Recipients have been delivered.",
      "invariant": true,
      "invariant_justification": "The aggregate delivery state must be consistent with its parts. Reporting a shipment as delivered when a recipient is still pending would be a false claim to the shipper.",
      "testable_assertion": "A Shipment with Recipients in statuses [delivered, pending] MUST have an aggregate status of 'partially_delivered' or 'in_progress', never 'delivered'."
    },
    {
      "id": "BR-7",
      "rule": "All existing single-recipient shipments MUST be migrated to the new model with their sole recipient preserved as-is with no data loss or behavioral change.",
      "invariant": true,
      "invariant_justification": "2 million production shipments represent contractual delivery obligations. Any data loss or semantic change during migration corrupts the historical record and may violate regulatory or contractual requirements.",
      "testable_assertion": "After migration, every one of the 2M existing shipments MUST have exactly one Recipient whose name, address, and phone number match the pre-migration values byte-for-byte."
    },
    {
      "id": "BR-8",
      "rule": "External partner APIs MUST continue to receive shipment data in the current single-recipient format until partners have migrated to a new API version.",
      "invariant": false,
      "invariant_justification": "This is a contractual and coordination policy. Partners will eventually migrate, but the timeline is negotiable — making this a policy, not a physics constraint.",
      "testable_assertion": "Partner API responses for multi-recipient shipments MUST return the Primary Recipient in the existing single-recipient field structure. No new fields may appear in the v1 API response."
    },
    {
      "id": "BR-9",
      "rule": "Every multi-recipient Shipment MUST designate exactly one Primary Recipient for backward-compatible integrations, billing, and communications.",
      "invariant": true,
      "invariant_justification": "Without a deterministic primary recipient, legacy systems, invoices, and partner APIs cannot resolve a canonical contact — leading to silent data corruption across integrations.",
      "testable_assertion": "A Shipment with multiple Recipients MUST have exactly one marked as primary. Removing the primary Recipient MUST either be blocked or auto-promote another Recipient to primary."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The creator provides zero Recipients",
      "then": "The system rejects creation with a validation error indicating at least one Recipient is required"
    },
    {
      "id": "AC-2",
      "given": "A Shipment exists with one Recipient",
      "when": "A second Recipient with a valid name, address, phone, and optional delivery preferences is added",
      "then": "The Shipment now has two Recipients, each with independent delivery status initialized to 'pending'"
    },
    {
      "id": "AC-3",
      "given": "A multi-recipient Shipment exists",
      "when": "Delivery is completed for one Recipient but not the other",
      "then": "The delivered Recipient's status is 'delivered', the other remains 'pending', and the Shipment aggregate status is 'partially_delivered'"
    },
    {
      "id": "AC-4",
      "given": "A legacy single-recipient Shipment exists in the pre-migration schema",
      "when": "The data migration runs",
      "then": "The Shipment has exactly one Recipient with all original field values preserved, that Recipient is marked as Primary, and delivery preferences are set to system defaults"
    },
    {
      "id": "AC-5",
      "given": "A multi-recipient Shipment exists with a Primary Recipient",
      "when": "A partner API requests shipment data via the v1 API",
      "then": "The response returns the Primary Recipient's data in the existing single-recipient format with no schema changes"
    },
    {
      "id": "AC-6",
      "given": "A Shipment exists with two Recipients",
      "when": "A user attempts to add a third Recipient with the same name and address as an existing one",
      "then": "The system rejects the addition with a duplicate recipient error"
    },
    {
      "id": "AC-7",
      "given": "A multi-recipient Shipment with Recipients A (primary) and B",
      "when": "Recipient A is removed from the Shipment",
      "then": "Recipient B is automatically promoted to Primary, OR the removal is blocked with an error requiring primary reassignment first"
    },
    {
      "id": "AC-8",
      "given": "A multi-recipient Shipment exists",
      "when": "A user attempts to remove the last remaining Recipient",
      "then": "The system rejects the removal, preserving the minimum-one-recipient invariant"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Multi-recipient shipment where all recipients share the same address but have different names (e.g., office building, multiple tenants)",
      "expected_behavior": "Allowed — the uniqueness constraint is on the (name, address) tuple, not address alone. Each recipient gets independent delivery status and preferences."
    },
    {
      "scenario": "Partner API receives a multi-recipient shipment but only supports single-recipient format",
      "expected_behavior": "The v1 API returns only the Primary Recipient. Partner must upgrade to v2 API to see all recipients. No silent data truncation warnings are needed in the response body, but internal logging should flag these for partner migration tracking."
    },
    {
      "scenario": "A Shipment is mid-delivery (courier en route) when a new Recipient is added",
      "expected_behavior": "System must define whether recipient list is mutable after dispatch. Likely: additions blocked once shipment is in 'in_transit' or later status. This needs explicit product decision."
    },
    {
      "scenario": "Migration of a shipment that is already in 'delivered' status",
      "expected_behavior": "Migrated as-is. The single recipient becomes Primary with status 'delivered'. The shipment aggregate status remains 'delivered'. No re-processing triggered."
    },
    {
      "scenario": "Billing and invoicing: who pays for a multi-recipient shipment?",
      "expected_behavior": "Billing model must be defined. Options: bill per-recipient (each is a separate delivery), bill per-shipment (flat rate regardless of recipients), or tiered pricing. This is a critical business decision that affects pricing, partner contracts, and revenue."
    },
    {
      "scenario": "Recipient B on a multi-recipient shipment has an address that is in a different delivery zone or country than Recipient A",
      "expected_behavior": "Routing and delivery logistics diverge. The system must decide if a multi-recipient shipment can span delivery zones or if all recipients must be within the same zone. Cross-zone recipients may require splitting into sub-shipments."
    },
    {
      "scenario": "Notifications: who gets shipment-level notifications vs recipient-level notifications?",
      "expected_behavior": "Each Recipient should receive only notifications relevant to their delivery. The Sender should receive aggregate shipment notifications. Delivery preferences per recipient may control notification channels."
    }
  ],

  "business_impact": {
    "financial": "Multi-recipient shipments introduce new pricing model complexity. Revenue opportunity if priced per-recipient. Revenue risk if existing flat-rate pricing is assumed to cover multiple deliveries. Migration itself is a cost center — 2M records require careful, likely zero-downtime migration with rollback capability. Partner API versioning has integration cost for both the platform and partners.",
    "operational": "Courier routing algorithms must account for multiple stops per shipment. Dispatch logic, delivery tracking, and exception handling all grow in complexity. Support teams need training on new shipment structures. Reporting and analytics must be updated — 'deliveries per shipment' is no longer always 1. SLA definitions may need revision: is the SLA per-recipient or per-shipment?",
    "user": "Senders gain flexibility to ship to multiple recipients in one operation. Recipients gain personalized delivery preferences. However, the UX must clearly communicate per-recipient status to avoid confusion. Existing users with single-recipient workflows must experience zero disruption.",
    "risk": "HIGH. This is a structural change to the core domain aggregate. Risks include: (1) Data migration failure on 2M records causing production outage, (2) Partner API breakage if backward compatibility is imperfect, (3) Billing inconsistencies if pricing model isn't defined before launch, (4) Domain model corruption if aggregate status derivation logic has bugs, (5) Performance degradation if queries that assumed 1:1 now face 1:N joins at scale.",
    "stakeholders_affected": [
      { "group": "Senders/Shippers", "impact": "New capability to send to multiple recipients per shipment. Must understand new pricing and status model." },
      { "group": "Recipients", "impact": "Gain personalized delivery preferences. No negative impact if migration is clean." },
      { "group": "Couriers/Drivers", "impact": "Multi-stop deliveries per shipment change route planning and delivery workflow. Mobile app must display per-recipient instructions." },
      { "group": "External Partners (API consumers)", "impact": "Must eventually migrate to v2 API to access multi-recipient data. v1 API returns degraded (primary-only) view in the interim. Risk of data inconsistency if partners make assumptions about 1:1 relationship." },
      { "group": "Finance/Billing Team", "impact": "Pricing model must be redefined. Invoicing logic must handle per-recipient or per-shipment billing. Revenue recognition may change." },
      { "group": "Customer Support", "impact": "Must handle new failure modes: partial delivery, per-recipient disputes, primary recipient confusion. Training required." },
      { "group": "Data/Analytics Team", "impact": "All dashboards, reports, and metrics that assume 1 shipment = 1 delivery must be updated. Historical data comparisons become complex." }
    ]
  },

  "confidence": {
    "level": 45,
    "reasoning": "The spec is structurally clear on the model change (1:1 to 1:N) but critically silent on several business-defining decisions: billing model, delivery zone constraints, mutability rules after dispatch, SLA definitions, and the exact semantics of 'delivery preferences.' These gaps mean any implementation built today would require guessing on revenue-impacting and operationally-critical behaviors. The partner API backward-compatibility strategy is implied but not specified. Multiple escalations are warranted.",
    "high_confidence_areas": [
      "The minimum-one-recipient invariant is unambiguous",
      "Per-recipient delivery status tracking is clearly required by the 1:N model",
      "Data migration must be lossless for 2M existing records",
      "Partner API backward compatibility is a hard requirement"
    ],
    "low_confidence_areas": [
      "Billing model for multi-recipient shipments is undefined",
      "Delivery zone constraints for recipients are unspecified",
      "Mutability of recipient list after shipment dispatch is unspecified",
      "Exact semantics and schema of 'delivery preferences' are undefined",
      "SLA model (per-shipment vs per-recipient) is unspecified",
      "Primary Recipient concept is inferred, not stated in the spec"
    ],
    "assumptions": [
      "A 'Primary Recipient' concept is needed for backward compatibility even though the spec doesn't mention it",
      "Delivery preferences include but are not limited to: time windows, safe-place, signature requirements",
      "The recipient list should be immutable once a shipment enters transit (common logistics pattern, but not stated)",
      "Partner APIs are versioned and a v2 can be introduced without breaking v1"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec says 'delivery preferences' without defining what preferences are available, their schema, or their default values. This is a core part of the new model and cannot be implemented without a concrete definition.",
      "affected_stakeholders": ["Recipients", "Couriers/Drivers", "Product Team", "Engineering"],
      "options": [
        "Define a fixed set of delivery preferences (time window, safe place, signature required, contactless)",
        "Make delivery preferences a flexible key-value store extensible without schema changes",
        "Start with a minimal set and extend via feature flags"
      ],
      "recommendation": "Define a minimal concrete set (time window, signature required, safe-place authorization) as V1. Use an extensible schema so new preferences can be added without migration."
    },
    {
      "type": "missing_context",
      "description": "No billing/pricing model defined for multi-recipient shipments. A shipment with 3 recipients to 3 different addresses is fundamentally different in cost from a single-recipient shipment. Without a pricing decision, the feature cannot be launched.",
      "affected_stakeholders": ["Finance/Billing Team", "Senders/Shippers", "External Partners"],
      "options": [
        "Bill per-recipient (each recipient = separate delivery charge)",
        "Bill per-shipment (flat rate regardless of recipient count)",
        "Tiered pricing (base + incremental per additional recipient)"
      ],
      "recommendation": "Per-recipient billing aligns with physical delivery cost reality. Recommend per-recipient as default with volume discounts as a business lever."
    },
    {
      "type": "missing_context",
      "description": "No specification on whether the recipient list can be modified after a shipment is dispatched (in-transit). Adding a recipient mid-delivery has massive routing, cost, and operational implications.",
      "affected_stakeholders": ["Couriers/Drivers", "Senders/Shippers", "Operations"],
      "options": [
        "Recipient list is immutable once shipment status moves past 'created'",
        "Recipients can be added until 'in_transit', then frozen",
        "Recipients can be added at any time, triggering re-routing"
      ],
      "recommendation": "Freeze the recipient list once the shipment enters 'dispatched' status. This is standard logistics practice and avoids mid-route chaos."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not define how multi-recipient shipments interact with delivery zones. Can one shipment have recipients in different cities or countries? This fundamentally changes routing, customs, and cost.",
      "affected_stakeholders": ["Operations", "Couriers/Drivers", "Finance/Billing Team"],
      "options": [
        "All recipients must be within the same delivery zone",
        "Cross-zone allowed but split into sub-routes internally",
        "No geographic constraint — fully flexible"
      ],
      "recommendation": "Constrain to same delivery zone in V1 to limit operational complexity. Cross-zone support can be a V2 feature."
    }
  ],

  "rejection_reasons": []
}

